const book: BibleBook = {
  id: '2corinthians',
  name: '2 Coríntios',
  englishName: '2 Corinthians',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'Paul, an apostle of Christ Jesus through the will of God, and Timothy our brother, to the assembly of God which is at Corinth, with all the saints who are in the whole of Achaia:', pt: 'Paulo, apóstolo de Cristo Jesus pela vontade de Deus, e o irmão Timóteo, à igreja de Deus que está em Corinto, com todos os santos que estão em toda a Acaia:' },
      { v: 2, en: 'Grace to you and peace from God our Father and the Lord Jesus Christ.', pt: 'Graça a vós, e paz da parte de Deus nosso Pai, e do Senhor Jesus Cristo.' },
      { v: 3, en: 'Blessed be the God and Father of our Lord Jesus Christ, the Father of mercies and God of all comfort;', pt: 'Bendito seja o Deus e Pai de nosso Senhor Jesus Cristo, o Pai das misericórdias e Deus de toda a consolação,' },
      { v: 4, en: 'who comforts us in all our affliction, that we may be able to comfort those who are in any affliction, through the comfort with which we ourselves are comforted by God.', pt: 'que nos consola em toda a nossa tribulação, para que também possamos consolar os que estiverem em alguma tribulação, pela consolação com que nós mesmos somos consolados por Deus.' },
      { v: 5, en: 'For as the sufferings of Christ abound to us, even so our comfort also abounds through Christ.', pt: 'Porque, como as aflições de Cristo transbordam para conosco, assim também por meio de Cristo transborda a nossa consolação.' },
      { v: 6, en: 'But if we are afflicted, it is for your comfort and salvation. If we are comforted, it is for your comfort, which produces in you the patient enduring of the same sufferings which we also suffer.', pt: 'Mas, se somos atribulados, é para vossa consolação e salvação; ou, se somos consolados, para vossa consolação é a qual se opera suportando com paciência as mesmas aflições que nós também padecemos;' },
      { v: 7, en: 'Our hope for you is steadfast, knowing that, since you are partakers of the sufferings, so also are you of the comfort.', pt: 'e a nossa esperança acerca de vós é firme, sabendo que, como sois participantes das aflições, assim o sereis também da consolação.' },
      { v: 8, en: 'For we don’t desire to have you uninformed, brothers, concerning our affliction which happened to us in Asia, that we were weighed down exceedingly, beyond our power, so much that we despaired even of life.', pt: 'Porque não queremos, irmãos, que ignoreis a tribulação que nos sobreveio na Ásia, pois que fomos sobremaneira oprimidos acima das nossas forças, de modo tal que até da vida desesperamos;' },
      { v: 9, en: 'Yes, we ourselves have had the sentence of death within ourselves, that we should not trust in ourselves, but in God who raises the dead,', pt: 'portanto já em nós mesmos tínhamos a sentença de morte, para que não confiássemos em nós, mas em Deus, que ressuscita os mortos;' },
      { v: 10, en: 'who delivered us out of so great a death, and does deliver; on whom we have set our hope that he will also still deliver us;', pt: 'o qual nos livrou de tão horrível morte, e livrará; em quem esperamos que também ainda nos livrará,' },
      { v: 11, en: 'you also helping together on our behalf by your supplication; that, for the gift given to us by means of many, thanks may be given by many persons on your behalf.', pt: 'ajudando-nos também vós com orações por nós, para que, pela mercê que por muitas pessoas nos foi feita, por muitas também sejam dadas graças a nosso respeito.' },
      { v: 12, en: 'For our boasting is this: the testimony of our conscience, that in holiness and sincerity of God, not in fleshly wisdom but in the grace of God we behaved ourselves in the world, and more abundantly toward you.', pt: 'Porque a nossa glória é esta: o testemunho da nossa consciência, de que em santidade e sinceridade de Deus, não em sabedoria carnal, mas na graça de Deus, temos vivido no mundo, e mormente em relação a vós.' },
      { v: 13, en: 'For we write no other things to you, than what you read or even acknowledge, and I hope you will acknowledge to the end;', pt: 'Pois outra coisa não vos escrevemos, senão as que ledes, ou mesmo reconheceis; e espero que também até o fim as reconhecereis;' },
      { v: 14, en: 'as also you acknowledged us in part, that we are your boasting, even as you also are ours, in the day of our Lord Jesus.', pt: 'como também já em parte nos reconhecestes, que somos a vossa glória, assim vós sereis a nossa no dia do Senhor Jesus.' },
      { v: 15, en: 'In this confidence, I was determined to come first to you, that you might have a second benefit;', pt: 'E nesta confiança quis primeiro ir ter convosco, para que recebêsseis um segundo benefício;' },
      { v: 16, en: 'and by you to pass into Macedonia, and again from Macedonia to come to you, and to be sent forward by you on my journey to Judea.', pt: 'e por vós passar à Macedônia, e da Macedônia voltar a vós, e ser por vosso intermédio encaminhado à Judéia.' },
      { v: 17, en: 'When I therefore was thus determined, did I show fickleness? Or the things that I purpose, do I purpose according to the flesh, that with me there should be the “Yes, yes” and the “No, no?”', pt: 'Ora, deliberando isto, usei porventura de leviandade? ou o que delibero, faço-o segundo a carne, para que haja comigo o sim, sim e o não não?' },
      { v: 18, en: 'But as God is faithful, our word toward you was not “Yes and no.”', pt: 'Antes, como Deus é fiel, a nossa palavra a vós não é sim e não,' },
      { v: 19, en: 'For the Son of God, Jesus Christ, who was preached among you by us, by me, Silvanus, and Timothy, was not “Yes and no,” but in him is “Yes.”', pt: 'porque o Filho de Deus, Cristo Jesus, que entre vós foi pregado por nós, isto é, por mim, Silvano e Timóteo, não foi sim e não; mas nele houve sim.' },
      { v: 20, en: 'For however many are the promises of God, in him is the “Yes.” Therefore also through him is the “Amen”, to the glory of God through us.', pt: 'Pois, tantas quantas forem as promessas de Deus, nele está o sim; portanto é por ele o amém, para glória de Deus por nosso intermédio.' },
      { v: 21, en: 'Now he who establishes us with you in Christ, and anointed us, is God;', pt: 'Mas aquele que nos confirma convosco em Cristo, e nos ungiu, é Deus,' },
      { v: 22, en: 'who also sealed us, and gave us the down payment of the Spirit in our hearts.', pt: 'o qual também nos selou e nos deu como penhor o Espírito em nossos corações.' },
      { v: 23, en: 'But I call God for a witness to my soul, that I didn’t come to Corinth to spare you.', pt: 'Ora, tomo a Deus por testemunha sobre a minha alma de que é para vos poupar que não fui mais a Corinto;' },
      { v: 24, en: 'Not that we control your faith, but are fellow workers with you for your joy. For you stand firm in faith.', pt: 'não que tenhamos domínio sobre a vossa fé, mas somos cooperadores de vosso gozo; pois pela fé estais firmados.' },
    ],
    2: [
      { v: 1, en: 'But I determined this for myself, that I would not come to you again in sorrow.', pt: 'Mas deliberei isto comigo mesmo: não ir mais ter convosco em tristeza.' },
      { v: 2, en: 'For if I make you sorry, then who will make me glad but he who is made sorry by me?', pt: 'Porque, se eu vos entristeço, quem é, pois, o que me alegra, senão aquele que por mim é entristecido?' },
      { v: 3, en: 'And I wrote this very thing to you, so that, when I came, I wouldn’t have sorrow from them of whom I ought to rejoice; having confidence in you all, that my joy would be shared by all of you.', pt: 'E escrevi isto mesmo, para que, chegando, eu não tenha tristeza da parte dos que deveriam alegrar-me; confiando em vós todos, que a minha alegria é a de todos vós.' },
      { v: 4, en: 'For out of much affliction and anguish of heart I wrote to you with many tears, not that you should be made sorry, but that you might know the love that I have so abundantly for you.', pt: 'Porque em muita tribulação e angústia de coração vos escrevi, com muitas lágrimas, não para que vos entristecêsseis, mas para que conhecêsseis o amor que abundantemente vos tenho.' },
      { v: 5, en: 'But if any has caused sorrow, he has caused sorrow, not to me, but in part (that I not press too heavily) to you all.', pt: 'Ora, se alguém tem causado tristeza, não me tem contristado a mim, mas em parte (para não ser por demais severo) a todos vós.' },
      { v: 6, en: 'This punishment which was inflicted by the many is sufficient for such a one;', pt: 'Basta a esse tal esta repreensão feita pela maioria.' },
      { v: 7, en: 'so that on the contrary you should rather forgive him and comfort him, lest by any means such a one should be swallowed up with his excessive sorrow.', pt: 'De maneira que, pelo contrário, deveis antes perdoar-lhe e consolá-lo, para que ele não seja devorado por excessiva tristeza.' },
      { v: 8, en: 'Therefore I beg you to confirm your love toward him.', pt: 'Pelo que vos rogo que confirmeis para com ele o vosso amor.' },
      { v: 9, en: 'For to this end I also wrote, that I might know the proof of you, whether you are obedient in all things.', pt: 'É pois para isso também que escrevi, para, por esta prova, saber se sois obedientes em tudo.' },
      { v: 10, en: 'Now I also forgive whomever you forgive anything. For if indeed I have forgiven anything, I have forgiven that one for your sakes in the presence of Christ,', pt: 'E a quem perdoardes alguma coisa, também eu; pois, o que eu também perdoei, se é que alguma coisa tenho perdoado, por causa de vós o fiz na presença de Cristo, para que Satanás não leve vantagem sobre nós;' },
      { v: 11, en: 'that no advantage may be gained over us by Satan; for we are not ignorant of his schemes.', pt: 'porque não ignoramos as suas maquinações.' },
      { v: 12, en: 'Now when I came to Troas for the Good News of Christ, and when a door was opened to me in the Lord,', pt: 'Ora, quando cheguei a Trôade para pregar o evangelho de Cristo, e quando se me abriu uma porta no Senhor,' },
      { v: 13, en: 'I had no relief for my spirit, because I didn’t find Titus, my brother, but taking my leave of them, I went out into Macedonia.', pt: 'não tive descanso no meu espírito, porque não achei ali irmão Tito; mas, despedindo-me deles, parti para a Macedônia.' },
      { v: 14, en: 'Now thanks be to God, who always leads us in triumph in Christ, and reveals through us the sweet aroma of his knowledge in every place.', pt: 'Graças, porém, a Deus que em Cristo sempre nos conduz em triunfo, e por meio de nós difunde em todo lugar o cheiro do seu conhecimento;' },
      { v: 15, en: 'For we are a sweet aroma of Christ to God, in those who are saved, and in those who perish;', pt: 'porque para Deus somos um aroma de Cristo, nos que se salvam e nos que se perdem.' },
      { v: 16, en: 'to the one a stench from death to death; to the other a sweet aroma from life to life. Who is sufficient for these things?', pt: 'Para uns, na verdade, cheiro de morte para morte; mas para outros cheiro de vida para vida. E para estas coisas quem é idôneo?' },
      { v: 17, en: 'For we are not as so many, peddling the word of God. But as of sincerity, but as of God, in the sight of God, we speak in Christ.', pt: 'Porque nós não somos falsificadores da palavra de Deus, como tantos outros; mas é com sinceridade, é da parte de Deus e na presença do próprio Deus que, em Cristo, falamos.' },
    ],
    3: [
      { v: 1, en: 'Are we beginning again to commend ourselves? Or do we need, as do some, letters of commendation to you or from you?', pt: 'Começamos outra vez a recomendar-nos a nós mesmos? Ou, porventura, necessitamos, como alguns, de cartas de recomendação para vós, ou de vós?' },
      { v: 2, en: 'You are our letter, written in our hearts, known and read by all men;', pt: 'Vós sois a nossa carta, escrita em nossos corações, conhecida e lida por todos os homens,' },
      { v: 3, en: 'being revealed that you are a letter of Christ, served by us, written not with ink, but with the Spirit of the living God; not in tablets of stone, but in tablets that are hearts of flesh.', pt: 'sendo manifestos como carta de Cristo, ministrada por nós, e escrita, não com tinta, mas com o Espírito do Deus vivo, não em tábuas de pedra, mas em tábuas de carne do coração.' },
      { v: 4, en: 'Such confidence we have through Christ toward God;', pt: 'E é por Cristo que temos tal confiança em Deus;' },
      { v: 5, en: 'not that we are sufficient of ourselves, to account anything as from ourselves; but our sufficiency is from God;', pt: 'não que sejamos capazes, por nós, de pensar alguma coisa, como de nós mesmos; mas a nossa capacidade vem de Deus,' },
      { v: 6, en: 'who also made us sufficient as servants of a new covenant; not of the letter, but of the Spirit. For the letter kills, but the Spirit gives life.', pt: 'o qual também nos capacitou para sermos ministros dum novo pacto, não da letra, mas do espírito; porque a letra mata, mas o espírito vivifica.' },
      { v: 7, en: 'But if the service of death, written engraved on stones, came with glory, so that the children of Israel could not look steadfastly on the face of Moses for the glory of his face, which was passing away;', pt: 'Ora, se o ministério da morte, gravado com letras em pedras, veio em glória, de maneira que os filhos de Israel não podiam fixar os olhos no rosto de Moisés, por causa da glória do seu rosto, a qual se estava desvanecendo,' },
      { v: 8, en: 'won’t service of the Spirit be with much more glory?', pt: 'como não será de maior glória o ministério do espírito?' },
      { v: 9, en: 'For if the service of condemnation has glory, the service of righteousness exceeds much more in glory.', pt: 'Porque, se o ministério da condenação tinha glória, muito mais excede em glória o ministério da justiça.' },
      { v: 10, en: 'For most certainly that which has been made glorious has not been made glorious in this respect, by reason of the glory that surpasses.', pt: 'Pois na verdade, o que foi feito glorioso, não o é em comparação com a glória inexcedível.' },
      { v: 11, en: 'For if that which passes away was with glory, much more that which remains is in glory.', pt: 'Porque, se aquilo que se desvanecia era glorioso, muito mais glorioso é o que permanece.' },
      { v: 12, en: 'Having therefore such a hope, we use great boldness of speech,', pt: 'Tendo, pois, tal esperança, usamos de muita ousadia no falar.' },
      { v: 13, en: 'and not as Moses, who put a veil on his face, that the children of Israel wouldn’t look steadfastly on the end of that which was passing away.', pt: 'E não somos como Moisés, que trazia um véu sobre o rosto, para que os filhos de Isra desvanecia;' },
      { v: 14, en: 'But their minds were hardened, for until this very day at the reading of the old covenant the same veil remains, because in Christ it passes away.', pt: 'mas o entendimento lhes ficou endurecido. Pois até o dia de hoje, à leitura do velho pacto, permanece o mesmo véu, não lhes sendo revelado que em Cristo é ele abolido;' },
      { v: 15, en: 'But to this day, when Moses is read, a veil lies on their heart.', pt: 'sim, até o dia de hoje, sempre que Moisés é lido, um véu está posto sobre o coração deles.' },
      { v: 16, en: 'But whenever one turns to the Lord, the veil is taken away.', pt: 'Contudo, convertendo-se um deles ao Senhor, é-lhe tirado o véu.' },
      { v: 17, en: 'Now the Lord is the Spirit and where the Spirit of the Lord is, there is liberty.', pt: 'Ora, o Senhor é o Espírito; e onde está o Espírito do Senhor aí há liberdade.' },
      { v: 18, en: 'But we all, with unveiled face seeing the glory of the Lord as in a mirror, are transformed into the same image from glory to glory, even as from the Lord, the Spirit.', pt: 'Mas todos nós, com rosto descoberto, refletindo como um espelho a glória do Senhor, somos transformados de glória em glória na mesma imagem, como pelo Espírito do Senhor.' },
    ],
    4: [
      { v: 1, en: 'Therefore seeing we have this ministry, even as we obtained mercy, we don’t faint.', pt: 'Pelo que, tendo este ministério, assim como já alcançamos misericórdia, não desfalecemos;' },
      { v: 2, en: 'But we have renounced the hidden things of shame, not walking in craftiness, nor handling the word of God deceitfully; but by the manifestation of the truth commending ourselves to every man’s conscience in the sight of God.', pt: 'pelo contrário, rejeitamos as coisas ocultas, que são vergonhosas, não andando com astúcia, nem adulterando a palavra de Deus; mas, pela manifestação da verdade, nós nos recomendamos à consciência de todos os homens diante de Deus.' },
      { v: 3, en: 'Even if our Good News is veiled, it is veiled in those who are dying;', pt: 'Mas, se ainda o nosso evangelho está encoberto, é naqueles que se perdem que está encoberto,' },
      { v: 4, en: 'in whom the god of this world has blinded the minds of the unbelieving, that the light of the Good News of the glory of Christ, who is the image of God, should not dawn on them.', pt: 'nos quais o deus deste século cegou os entendimentos dos incrédulos, para que lhes não resplandeça a luz do evangelho da glória de Cristo, o qual é a imagem de Deus.' },
      { v: 5, en: 'For we don’t preach ourselves, but Christ Jesus as Lord, and ourselves as your servants for Jesus’ sake;', pt: 'Pois não nos pregamos a nós mesmos, mas a Cristo Jesus como Senhor; e a nós mesmos como vossos servos por amor de Jesus.' },
      { v: 6, en: 'seeing it is God who said, “Light will shine out of darkness,” who has shone in our hearts, to give the light of the knowledge of the glory of God in the face of Jesus Christ.', pt: 'Porque Deus, que disse: Das trevas brilhará a luz, é quem brilhou em nossos corações, para iluminação do conhecimento da glória de Deus na face de Cristo.' },
      { v: 7, en: 'But we have this treasure in clay vessels, that the exceeding greatness of the power may be of God, and not from ourselves.', pt: 'Temos, porém, este tesouro em vasos de barro, para que a excelência do poder seja de Deus, e não da nossa parte.' },
      { v: 8, en: 'We are pressed on every side, yet not crushed; perplexed, yet not to despair;', pt: 'Em tudo somos atribulados, mas não angustiados; perplexos, mas não desesperados;' },
      { v: 9, en: 'pursued, yet not forsaken; struck down, yet not destroyed;', pt: 'perseguidos, mas não desamparados; abatidos, mas não destruídos;' },
      { v: 10, en: 'always carrying in the body the putting to death of the Lord Jesus, that the life of Jesus may also be revealed in our body.', pt: 'trazendo sempre no corpo o morrer de Jesus, para que também a vida de Jesus se manifeste em nossos corpos;' },
      { v: 11, en: 'For we who live are always delivered to death for Jesus’ sake, that the life also of Jesus may be revealed in our mortal flesh.', pt: 'pois nós, que vivemos, estamos sempre entregues à morte por amor de Jesus, para que também a vida de Jesus se manifeste em nossa carne mortal.' },
      { v: 12, en: 'So then death works in us, but life in you.', pt: 'De modo que em nós opera a morte, mas em vós a vida.' },
      { v: 13, en: 'But having the same spirit of faith, according to that which is written, “I believed, and therefore I spoke.” We also believe, and therefore also we speak;', pt: 'Ora, temos o mesmo espírito de fé, conforme está escrito: Cri, por isso falei; também nós cremos, por isso também falamos,' },
      { v: 14, en: 'knowing that he who raised the Lord Jesus will raise us also with Jesus, and will present us with you.', pt: 'sabendo que aquele que ressucitou o Senhor Jesus, nos ressuscitará a nós com Jesus, e nos apresentará convosco.' },
      { v: 15, en: 'For all things are for your sakes, that the grace, being multiplied through the many, may cause the thanksgiving to abound to the glory of God.', pt: 'Pois tudo é por amor de vós, para que a graça, multiplicada por meio de muitos, faça abundar a ação de graças para glória de Deus.' },
      { v: 16, en: 'Therefore we don’t faint, but though our outward man is decaying, yet our inward man is renewed day by day.', pt: 'Por isso não desfalecemos; mas ainda que o nosso homem exterior se esteja consumindo, o interior, contudo, se renova de dia em dia.' },
      { v: 17, en: 'For our light affliction, which is for the moment, works for us more and more exceedingly an eternal weight of glory;', pt: 'Porque a nossa leve e momentânea tribulação produz para nós cada vez mais abundantemente um eterno peso de glória;' },
      { v: 18, en: 'while we don’t look at the things which are seen, but at the things which are not seen. For the things which are seen are temporal, but the things which are not seen are eternal.', pt: 'não atentando nós nas coisas que se vêem, mas sim nas que se não vêem; porque as que se vêem são temporais, enquanto as que se não vêem são eternas.' },
    ],
    5: [
      { v: 1, en: 'For we know that if the earthly house of our tent is dissolved, we have a building from God, a house not made with hands, eternal, in the heavens.', pt: 'Porque sabemos que, se a nossa casa terrestre deste tabernáculo se desfizer, temos de Deus um edifício, uma casa não feita por mãos, eterna, nos céus.' },
      { v: 2, en: 'For most certainly in this we groan, longing to be clothed with our habitation which is from heaven;', pt: 'Pois neste tabernáculo nós gememos, desejando muito ser revestidos da nossa habitação que é do céu,' },
      { v: 3, en: 'if so be that being clothed we will not be found naked.', pt: 'se é que, estando vestidos, não formos achados nus.' },
      { v: 4, en: 'For indeed we who are in this tent do groan, being burdened; not that we desire to be unclothed, but that we desire to be clothed, that what is mortal may be swallowed up by life.', pt: 'Porque, na verdade, nós, os que estamos neste tabernáculo, gememos oprimidos, porque não queremos ser despidos, mas sim revestidos, para que o mortal seja absorvido pela vida.' },
      { v: 5, en: 'Now he who made us for this very thing is God, who also gave to us the down payment of the Spirit.', pt: 'Ora, quem para isto mesmo nos preparou foi Deus, o qual nos deu como penhor o Espírito.' },
      { v: 6, en: 'Therefore we are always confident and know that while we are at home in the body, we are absent from the Lord;', pt: 'Temos, portanto, sempre bom ânimo, sabendo que, enquanto estamos presentes no corpo, estamos ausentes do Senhor' },
      { v: 7, en: 'for we walk by faith, not by sight.', pt: '(porque andamos por fé, e não por vista);' },
      { v: 8, en: 'We are courageous, I say, and are willing rather to be absent from the body, and to be at home with the Lord.', pt: 'temos bom ânimo, mas desejamos antes estar ausentes deste corpo, para estarmos presentes com o Senhor.' },
      { v: 9, en: 'Therefore also we make it our aim, whether at home or absent, to be well pleasing to him.', pt: 'Pelo que também nos esforçamos para ser-lhe agradáveis, quer presentes, quer ausentes.' },
      { v: 10, en: 'For we must all be revealed before the judgment seat of Christ; that each one may receive the things in the body, according to what he has done, whether good or bad.', pt: 'Porque é necessário que todos nós sejamos manifestos diante do tribunal de Cristo, para que cada um receba o que fez por meio do corpo, segundo o que praticou, o bem ou o mal.' },
      { v: 11, en: 'Knowing therefore the fear of the Lord, we persuade men, but we are revealed to God; and I hope that we are revealed also in your consciences.', pt: 'Portanto, conhecendo o temor do Senhor, procuramos persuadir os homens; mas, a Deus já somos manifestos, e espero que também nas vossas consciências sejamos manifestos.' },
      { v: 12, en: 'For we are not commending ourselves to you again, but speak as giving you occasion of boasting on our behalf, that you may have something to answer those who boast in appearance, and not in heart.', pt: 'Não nos recomendamos outra vez a vós, mas damo-vos ocasião de vos gloriardes por nossa causa, a fim de que tenhais resposta para os que se gloriam na aparência, e não no coração.' },
      { v: 13, en: 'For if we are beside ourselves, it is for God. Or if we are of sober mind, it is for you.', pt: 'Porque, se enlouquecemos, é para Deus; se conservamos o juízo, é para vós.' },
      { v: 14, en: 'For the love of Christ constrains us; because we judge thus, that one died for all, therefore all died.', pt: 'Pois o amor de Cristo nos constrange, porque julgamos assim: se um morreu por todos, logo todos morreram;' },
      { v: 15, en: 'He died for all, that those who live should no longer live to themselves, but to him who for their sakes died and rose again.', pt: 'e ele morreu por todos, para que os que vivem não vivam mais para si, mas para aquele que por eles morreu e ressuscitou.' },
      { v: 16, en: 'Therefore we know no one after the flesh from now on. Even though we have known Christ after the flesh, yet now we know him so no more.', pt: 'Por isso daqui por diante a ninguém conhecemos segundo a carne; e, ainda que tenhamos conhecido Cristo segundo a carne, contudo agora já não o conhecemos desse modo.' },
      { v: 17, en: 'Therefore if anyone is in Christ, he is a new creation. The old things have passed away. Behold, all things have become new.', pt: 'Pelo que, se alguém está em Cristo, nova criatura é; as coisas velhas já passaram; eis que tudo se fez novo.' },
      { v: 18, en: 'But all things are of God, who reconciled us to himself through Jesus Christ, and gave to us the ministry of reconciliation;', pt: 'Mas todas as coisas provêm de Deus, que nos reconciliou consigo mesmo por Cristo, e nos confiou o ministério da reconciliação;' },
      { v: 19, en: 'namely, that God was in Christ reconciling the world to himself, not reckoning to them their trespasses, and having committed to us the word of reconciliation.', pt: 'pois que Deus estava em Cristo reconciliando consigo o mundo, não imputando aos homens as suas transgressões; e nos encarregou da palavra da reconciliação.' },
      { v: 20, en: 'We are therefore ambassadors on behalf of Christ, as though God were entreating by us: we beg you on behalf of Christ, be reconciled to God.', pt: 'De sorte que somos embaixadores por Cristo, como se Deus por nós vos exortasse. Rogamo-vos, pois, por Cristo que vos reconcilieis com Deus.' },
      { v: 21, en: 'For him who knew no sin he made to be sin on our behalf; so that in him we might become the righteousness of God.', pt: 'Âquele que não conheceu pecado, Deus o fez pecado por nós; para que nele fôssemos feitos justiça de Deus.' },
    ],
    6: [
      { v: 1, en: 'Working together, we entreat also that you do not receive the grace of God in vain,', pt: 'E nós, cooperando com ele, também vos exortamos a que não recebais a graça de Deus em vão;' },
      { v: 2, en: 'for he says, “At an acceptable time I listened to you, in a day of salvation I helped you.” Behold, now is the acceptable time. Behold, now is the day of salvation.', pt: '(porque diz: No tempo aceitável te escutei e no dia da salvação te socorri; eis aqui agora o tempo aceitável, eis aqui agora o dia da salvação);' },
      { v: 3, en: 'We give no occasion of stumbling in anything, that our service may not be blamed,', pt: 'não dando nós nenhum motivo de escândalo em coisa alguma, para que o nosso ministério não seja censurado;' },
      { v: 4, en: 'but in everything commending ourselves, as servants of God, in great endurance, in afflictions, in hardships, in distresses,', pt: 'antes em tudo recomendando-nos como ministros de Deus; em muita perseverança, em aflições, em necessidades, em angústias,' },
      { v: 5, en: 'in beatings, in imprisonments, in riots, in labors, in watchings, in fastings;', pt: 'em açoites, em prisões, em tumultos, em trabalhos, em vigílias, em jejuns,' },
      { v: 6, en: 'in pureness, in knowledge, in perseverance, in kindness, in the Holy Spirit, in sincere love,', pt: 'na pureza, na ciência, na longanimidade, na bondade, no Espírito Santo, no amor não fingido,' },
      { v: 7, en: 'in the word of truth, in the power of God; by the armor of righteousness on the right hand and on the left,', pt: 'na palavra da verdade, no poder de Deus, pelas armas da justiça à direita e à esquerda,' },
      { v: 8, en: 'by glory and dishonor, by evil report and good report; as deceivers, and yet true;', pt: 'por honra e por desonra, por má fama e por boa fama; como enganadores, porém verdadeiros;' },
      { v: 9, en: 'as unknown, and yet well known; as dying, and behold, we live; as punished, and not killed;', pt: 'como desconhecidos, porém bem conhecidos; como quem morre, e eis que vivemos; como castigados, porém não mortos;' },
      { v: 10, en: 'as sorrowful, yet always rejoicing; as poor, yet making many rich; as having nothing, and yet possessing all things.', pt: 'como entristecidos, mas sempre nos alegrando; como pobres, mas enriquecendo a muitos; como nada tendo, mas possuindo tudo.' },
      { v: 11, en: 'Our mouth is open to you, Corinthians. Our heart is enlarged.', pt: 'ç coríntios, a nossa boca está aberta para vós, o nosso coração está dilatado!' },
      { v: 12, en: 'You are not restricted by us, but you are restricted by your own affections.', pt: 'Não estais estreitados em nós; mas estais estreitados nos vossos próprios afetos.' },
      { v: 13, en: 'Now in return, I speak as to my children, you also open your hearts.', pt: 'Ora, em recompensa disto (falo como a filhos), dilatai-vos também vós.' },
      { v: 14, en: 'Don’t be unequally yoked with unbelievers, for what fellowship have righteousness and iniquity? Or what fellowship has light with darkness?', pt: 'Não vos prendais a um jugo desigual com os incrédulos; pois que sociedade tem a justiça com a injustiça? ou que comunhão tem a luz com as trevas?' },
      { v: 15, en: 'What agreement has Christ with Belial? Or what portion has a believer with an unbeliever?', pt: 'Que harmonia há entre Cristo e Belial? ou que parte tem o crente com o incrédulo?' },
      { v: 16, en: 'What agreement has a temple of God with idols? For you are a temple of the living God. Even as God said, “I will dwell in them, and walk in them; and I will be their God, and they will be my people.”', pt: 'E que consenso tem o santuário de Deus com ídolos? Pois nós somos santuário de Deus vivo, como Deus disse: Neles habitarei, e entre eles andarei; e eu serei o seu Deus e eles serão o meu povo.' },
      { v: 17, en: 'Therefore “‘Come out from among them, and be separate,’ says the Lord. ‘Touch no unclean thing. I will receive you.', pt: 'Pelo que, saí vós do meio deles e separai-vos, diz o Senhor; e não toqueis coisa imunda, e eu vos receberei;' },
      { v: 18, en: 'I will be to you a Father. You will be to me sons and daughters,’ says the Lord Almighty.”', pt: 'e eu serei para vós Pai, e vós sereis para mim filhos e filhas, diz o Senhor Todo-Poderoso.' },
    ],
    7: [
      { v: 1, en: 'Having therefore these promises, beloved, let us cleanse ourselves from all defilement of flesh and spirit, perfecting holiness in the fear of God.', pt: 'Ora, amados, visto que temos tais promessas, purifiquemo-nos de toda a imundícia da carne e do espírito, aperfeiçoando a santidade no temor de Deus.' },
      { v: 2, en: 'Open your hearts to us. We wronged no one. We corrupted no one. We took advantage of no one.', pt: 'Recebei-nos em vossos corações; a ninguém fizemos injustiça, a ninguém corrompemos, a ninguém exploramos.' },
      { v: 3, en: 'I say this not to condemn you, for I have said before, that you are in our hearts to die together and live together.', pt: 'Não o digo para vos condenar, pois já tenho declarado que estais em nossos corações para juntos morrermos e juntos vivermos.' },
      { v: 4, en: 'Great is my boldness of speech toward you. Great is my boasting on your behalf. I am filled with comfort. I overflow with joy in all our affliction.', pt: 'Grande é a minha franqueza para convosco, e muito me glorio a respeito de vós; estou cheio de consolação, transbordo de gozo em todas as nossas tribulações.' },
      { v: 5, en: 'For even when we had come into Macedonia, our flesh had no relief, but we were afflicted on every side. Fightings were outside. Fear was inside.', pt: 'Porque, mesmo quando chegamos à Macedônia, a nossa carne não teve repouso algum; antes em tudo fomos atribulados: por fora combates, temores por dentro.' },
      { v: 6, en: 'Nevertheless, he who comforts the lowly, God, comforted us by the coming of Titus;', pt: 'Mas Deus, que consola os abatidos, nos consolou com a vinda de Tito;' },
      { v: 7, en: 'and not by his coming only, but also by the comfort with which he was comforted in you, while he told us of your longing, your mourning, and your zeal for me; so that I rejoiced still more.', pt: 'e não somente com a sua vinda, mas também pela consolação com que foi consolado a vosso respeito, enquanto nos referia as vossas saudações, o vosso pranto, o vosso zelo por mim, de modo que ainda mais me regozijei.' },
      { v: 8, en: 'For though I made you sorry with my letter, I do not regret it, though I did regret it. For I see that my letter made you sorry, though just for a while.', pt: 'Porquanto, ainda que vos contristei com a minha carta, não me arrependo; embora antes me tivesse arrependido (pois vejo que aquela carta vos contristou, ainda que por pouco tempo),' },
      { v: 9, en: 'I now rejoice, not that you were made sorry, but that you were made sorry to repentance. For you were made sorry in a godly way, that you might suffer loss by us in nothing.', pt: 'agora folgo, não porque fostes contristados, mas porque o fostes para o arrependimento; pois segundo Deus fostes contristados, para que por nós não sofrêsseis dano em coisa alguma.' },
      { v: 10, en: 'For godly sorrow produces repentance to salvation, which brings no regret. But the sorrow of the world produces death.', pt: 'Porque a tristeza segundo Deus opera arrependimento para a salvação, o qual não traz pesar; mas a tristeza do mundo opera a morte.' },
      { v: 11, en: 'For behold, this same thing, that you were made sorry in a godly way, what earnest care it worked in you. Yes, what defense, indignation, fear, longing, zeal, and vengeance! In everything you demonstrated yourselves to be pure in the matter.', pt: 'Pois vêde quanto cuidado não produziu em vós isto mesmo, o serdes contristados segundo Deus! sim, que defesa própria, que indignação, que temor, que saudades, que zelo, que vingança! Em tudo provastes estar inocentes nesse negócio.' },
      { v: 12, en: 'So although I wrote to you, I wrote not for his cause that did the wrong, nor for his cause that suffered the wrong, but that your earnest care for us might be revealed in you in the sight of God.', pt: 'Portanto, ainda que vos escrevi, não foi por causa do que fez o mal, nem por causa do que o sofreu, mas para que fosse manifesto, diante de Deus, o vosso grande cuidado por nós.' },
      { v: 13, en: 'Therefore we have been comforted. In our comfort we rejoiced the more exceedingly for the joy of Titus, because his spirit has been refreshed by you all.', pt: 'Por isso temos sido consolados. E em nossa consolação nos alegramos ainda muito mais pela alegria de Tito, porque o seu espírito tem sido recreado por vós todos.' },
      { v: 14, en: 'For if in anything I have boasted to him on your behalf, I was not disappointed. But as we spoke all things to you in truth, so our glorying also which I made before Titus was found to be truth.', pt: 'Porque, se em alguma coisa me gloriei de vós para com ele, não fiquei envergonhado; mas como vos dissemos tudo com verdade, assim também o louvor que de vós fizemos a Tito se achou verdadeiro.' },
      { v: 15, en: 'His affection is more abundantly toward you, while he remembers all of your obedience, how with fear and trembling you received him.', pt: 'E o seu entranhável afeto para convosco é mais abundante, lembrando-se da obediência de vós todos, e de como o recebestes com temor e tremor.' },
      { v: 16, en: 'I rejoice that in everything I am confident concerning you.', pt: 'Regozijo-me porque em tudo tenho confiança em vós.' },
    ],
    8: [
      { v: 1, en: 'Moreover, brothers, we make known to you the grace of God which has been given in the assemblies of Macedonia;', pt: 'Também, irmãos, vos fazemos conhecer a graça de Deus que foi dada às igrejas da Mecedônia;' },
      { v: 2, en: 'how that in much proof of affliction the abundance of their joy and their deep poverty abounded to the riches of their generosity.', pt: 'como, em muita prova de tribulação, a abundância do seu gozo e sua profunda pobreza abundaram em riquezas da sua generosidade.' },
      { v: 3, en: 'For according to their power, I testify, yes and beyond their power, they gave of their own accord,', pt: 'Porque, dou-lhes testemunho de que, segundo as suas posses, e ainda acima das suas posses, deram voluntariamente,' },
      { v: 4, en: 'begging us with much entreaty to receive this grace and the fellowship in the service to the saints.', pt: 'pedindo-nos, com muito encarecimento, o privilégio de participarem deste serviço a favor dos santos;' },
      { v: 5, en: 'This was not as we had expected, but first they gave their own selves to the Lord, and to us through the will of God.', pt: 'e não somente fizeram como nós esperávamos, mas primeiramente a si mesmos se deram ao Senhor, e a nós pela vontade de Deus;' },
      { v: 6, en: 'So we urged Titus, that as he had made a beginning before, so he would also complete in you this grace.', pt: 'de maneira que exortamos a Tito que, assim como antes tinha começado, assim também completasse entre vós ainda esta graça.' },
      { v: 7, en: 'But as you abound in everything, in faith, utterance, knowledge, all earnestness, and in your love to us, see that you also abound in this grace.', pt: 'Ora, assim como abundais em tudo: em fé, em palavra, em ciência, em todo o zelo, no vosso amor para conosco, vede que também nesta graça abundeis.' },
      { v: 8, en: 'I speak not by way of commandment, but as proving through the earnestness of others the sincerity also of your love.', pt: 'Não digo isto como quem manda, mas para provar, mediante o zelo de outros, a sinceridade de vosso amor;' },
      { v: 9, en: 'For you know the grace of our Lord Jesus Christ, that, though he was rich, yet for your sakes he became poor, that you through his poverty might become rich.', pt: 'pois conheceis a graça de nosso Senhor Jesus Cristo, que, sendo rico, por amor de vós se fez pobre, para que pela sua pobreza fôsseis enriquecidos.' },
      { v: 10, en: 'I give a judgment in this: for this is expedient for you, who were the first to start a year ago, not only to do, but also to be willing.', pt: 'E nisto dou o meu parecer; pois isto vos convém a vós que primeiro começastes, desde o ano passado, não só a participar mas também a querer;' },
      { v: 11, en: 'But now complete the doing also, that as there was the readiness to be willing, so there may be the completion also out of your ability.', pt: 'agora, pois, levai a termo a obra, para que, assim como houve a prontidão no querer, haja também o cumprir segundo o que tendes.' },
      { v: 12, en: 'For if the readiness is there, it is acceptable according to what you have, not according to what you don’t have.', pt: 'Porque, se há prontidão de vontade, é aceitável segundo o que alguém tem, e não segundo o que não tem.' },
      { v: 13, en: 'For this is not that others may be eased and you distressed,', pt: 'Pois digo isto não para que haja alívio para outros e aperto para vós,' },
      { v: 14, en: 'but for equality. Your abundance at this present time supplies their lack, that their abundance also may become a supply for your lack; that there may be equality.', pt: 'mas para que haja igualdade, suprindo, neste tempo presente, na vossa abundância a falta dos outros, para que também a abundância deles venha a suprir a vossa falta, e assim haja igualdade;' },
      { v: 15, en: 'As it is written, “He who gathered much had nothing left over, and he who gathered little had no lack.”', pt: 'como está escrito: Ao que muito colheu, não sobrou; e ao que pouco colheu, não faltou.' },
      { v: 16, en: 'But thanks be to God, who puts the same earnest care for you into the heart of Titus.', pt: 'Mas, graças a Deus, que pôs no coração de Tito a mesma solicitude por vós;' },
      { v: 17, en: 'For he indeed accepted our exhortation, but being himself very earnest, he went out to you of his own accord.', pt: 'pois, com efeito, aceitou a nossa exortação; mas sendo sobremodo zeloso, foi por sua própria vontade que partiu para vós.' },
      { v: 18, en: 'We have sent together with him the brother whose praise in the Good News is known throughout all the assemblies.', pt: 'E juntamente com ele enviamos o irmão cujo louvor no evangelho se tem espalhado por todas as igrejas;' },
      { v: 19, en: 'Not only so, but he was also appointed by the assemblies to travel with us in this grace, which is served by us to the glory of the Lord himself, and to show our readiness.', pt: 'e não só isto, mas também foi escolhido pelas igrejas para ser nosso companheiro de viagem no tocante a esta graça que por nós é ministrada para glória do Senhor e para provar a nossa boa vontade;' },
      { v: 20, en: 'We are avoiding this, that any man should blame us concerning this abundance which is administered by us.', pt: 'assim evitando que alguém nos censure com referência a esta abundância, que por nós é ministrada;' },
      { v: 21, en: 'Having regard for honorable things, not only in the sight of the Lord, but also in the sight of men.', pt: 'pois zelamos o que é honesto, não só diante do Senhor, mas também diante dos homens.' },
      { v: 22, en: 'We have sent with them our brother, whom we have many times proved earnest in many things, but now much more earnest, by reason of the great confidence which he has in you.', pt: 'Com eles enviamos também outro nosso irmão, o qual muitas vezes e em muitas coisas já experimentamos ser zeloso, mas agora muito mais zeloso ainda pela muita confiança que vós tem.' },
      { v: 23, en: 'As for Titus, he is my partner and fellow worker for you. As for our brothers, they are the apostles of the assemblies, the glory of Christ.', pt: 'Quanto a Tito, ele é meu companheiro e cooperador para convosco; quanto a nosssos irmãos, são mensageiros das igrejas, glória de Cristo.' },
      { v: 24, en: 'Therefore show the proof of your love to them before the assemblies, and of our boasting on your behalf.', pt: 'Portanto mostrai para com eles, perante a face das igrejas, a prova do vosso amor, e da nossa glória a vosso respeito.' },
    ],
    9: [
      { v: 1, en: 'It is indeed unnecessary for me to write to you concerning the service to the saints,', pt: 'Pois quanto à ministração que se faz a favor dos santos, não necessito escrever-vos;' },
      { v: 2, en: 'for I know your readiness, of which I boast on your behalf to them of Macedonia, that Achaia has been prepared for a year past. Your zeal has stirred up very many of them.', pt: 'porque bem sei a vossa prontidão, pela qual me glorio de vós perante os macedônios, dizendo que a Acaia está pronta desde o ano passado; e o vosso zelo tem estimulado muitos.' },
      { v: 3, en: 'But I have sent the brothers that our boasting on your behalf may not be in vain in this respect, that, just as I said, you may be prepared,', pt: 'Mas enviei estes irmãos, a fim de que neste particular não se torne vão o nosso louvor a vosso respeito; para que, como eu dizia, estejais preparados,' },
      { v: 4, en: 'lest by any means, if anyone from Macedonia comes there with me and finds you unprepared, we (to say nothing of you) would be disappointed in this confident boasting.', pt: 'a fim de, se acaso alguns macedônios forem comigo, e vos acharem desaparecidos, não sermos nós envergonhados (para não dizermos vós) nesta confiança.' },
      { v: 5, en: 'I thought it necessary therefore to entreat the brothers that they would go before to you, and arrange ahead of time the generous gift that you promised before, that the same might be ready as a matter of generosity, and not of greediness.', pt: 'Portanto, julguei necessário exortar estes irmãos que fossem adiante ter convosco, e preparassem de antemão a vossa beneficência, já há tempos prometida, para que a mesma esteja pronta como beneficência e não como por extorsão.' },
      { v: 6, en: 'Remember this: he who sows sparingly will also reap sparingly. He who sows bountifully will also reap bountifully.', pt: 'Mas digo isto: Aquele que semeia pouco, pouco também ceifará; e aquele que semeia em abundância, em abundância também ceifará,' },
      { v: 7, en: 'Let each man give according as he has determined in his heart; not grudgingly, or under compulsion; for God loves a cheerful giver.', pt: 'Cada um contribua segundo propôs no seu coração; não com tristeza, nem por constrangimento; porque Deus ama ao que dá com alegria.' },
      { v: 8, en: 'And God is able to make all grace abound to you, that you, always having all sufficiency in everything, may abound to every good work.', pt: 'E Deus é poderoso para fazer abundar em vós toda a graça, a fim de que, tendo sempre, em tudo, toda a suficiência, abundeis em toda boa obra;' },
      { v: 9, en: 'As it is written, “He has scattered abroad, he has given to the poor. His righteousness remains forever.”', pt: 'conforme está escrito: Espalhou, deu aos pobres; a sua justiça permanece para sempre.' },
      { v: 10, en: 'Now may he who supplies seed to the sower and bread for food, supply and multiply your seed for sowing, and increase the fruits of your righteousness;', pt: 'Ora, aquele que dá a semente ao que semeia, e pão para comer, também dará e multiplicará a vossa sementeira, e aumentará os frutos da vossa justiça.' },
      { v: 11, en: 'you being enriched in everything to all generosity, which produces through us thanksgiving to God.', pt: 'enquanto em tudo enriqueceis para toda a liberalidade, a qual por nós reverte em ações de graças a Deus.' },
      { v: 12, en: 'For this service of giving that you perform not only makes up for lack among the saints, but abounds also through much giving of thanks to God;', pt: 'Porque a ministração deste serviço não só supre as necessidades dos santos, mas também transborda em muitas ações de graças a Deus;' },
      { v: 13, en: 'seeing that through the proof given by this service, they glorify God for the obedience of your confession to the Good News of Christ, and for the generosity of your contribution to them and to all;', pt: 'visto como, na prova desta ministração, eles glorificam a Deus pela submissão que confessais quanto ao evangelho de Cristo, e pela liberalidade da vossa contribuição para eles, e para todos;' },
      { v: 14, en: 'while they themselves also, with supplication on your behalf, yearn for you by reason of the exceeding grace of God in you.', pt: 'enquanto eles, pela oração por vós, demonstram o ardente afeto que vos têm, por causa da superabundante graça de Deus que há em vós.' },
      { v: 15, en: 'Now thanks be to God for his unspeakable gift!', pt: 'Graças a Deus pelo seu dom inefável.' },
    ],
    10: [
      { v: 1, en: 'Now I Paul, myself, entreat you by the humility and gentleness of Christ; I who in your presence am lowly among you, but being absent am bold toward you.', pt: 'Ora eu mesmo, Paulo, vos rogo pela mansidão e benignidade de Cristo, eu que, na verdade, quando presente entre vós, sou humilde, mas quando ausente, ousado para convosco;' },
      { v: 2, en: 'Yes, I beg you that I may not, when present, show courage with the confidence with which I intend to be bold against some, who consider us to be walking according to the flesh.', pt: 'sim, eu vos rogo que, quando estiver presente, não me veja obrigado a usar, com confiança, da ousadia que espero ter para com alguns que nos julgam como se andássemos segundo a carne.' },
      { v: 3, en: 'For though we walk in the flesh, we don’t wage war according to the flesh;', pt: 'Porque, embora andando na carne, não militamos segundo a carne,' },
      { v: 4, en: 'for the weapons of our warfare are not of the flesh, but mighty before God to the throwing down of strongholds,', pt: 'pois as armas da nossa milícia não são carnais, mas poderosas em Deus, para demolição de fortalezas;' },
      { v: 5, en: 'throwing down imaginations and every high thing that is exalted against the knowledge of God, and bringing every thought into captivity to the obedience of Christ;', pt: 'derribando raciocínios e todo baluarte que se ergue contra o conhecimento de Deus, e levando cativo todo pensamento à obediência a Cristo;' },
      { v: 6, en: 'and being in readiness to avenge all disobedience, when your obedience will be made full.', pt: 'e estando prontos para vingar toda desobediência, quando for cumprida a vossa obediência.' },
      { v: 7, en: 'Do you look at things only as they appear in front of your face? If anyone trusts in himself that he is Christ’s, let him consider this again with himself, that, even as he is Christ’s, so also we are Christ’s.', pt: 'Olhais para as coisas segundo a aparência. Se alguém confia de si mesmo que é de Cristo, pense outra vez isto consigo, que, assim como ele é de Cristo, também nós o somos.' },
      { v: 8, en: 'For though I should boast somewhat abundantly concerning our authority, (which the Lord gave for building you up, and not for casting you down) I will not be disappointed,', pt: 'Pois, ainda que eu me glorie um tanto mais da nossa autoridade, a qual o Senhor nos deu para edificação, e não para vossa destruição, não me envergonharei;' },
      { v: 9, en: 'that I may not seem as if I desire to terrify you by my letters.', pt: 'para que eu não pareça como se quisera intimidar-vos por cartas.' },
      { v: 10, en: 'For, “His letters”, they say, “are weighty and strong, but his bodily presence is weak, and his speech is despised.”', pt: 'Porque eles dizem: As cartas dele são graves e fortes, mas a sua presença corporal é fraca, e a sua palavra desprezível.' },
      { v: 11, en: 'Let such a person consider this, that what we are in word by letters when we are absent, such are we also in deed when we are present.', pt: 'Considere o tal isto, que, quais somos no falar por cartas, estando ausentes, tais seremos também no fazer, estando presentes,' },
      { v: 12, en: 'For we are not bold to number or compare ourselves with some of those who commend themselves. But they themselves, measuring themselves by themselves, and comparing themselves with themselves, are without understanding.', pt: 'pois não ousamos contar-nos, ou comparar-nos com alguns, que se louvam a si mesmos; mas estes, medindo-se consigo mesmos e comparando-se consigo mesmos, estão sem entendimento.' },
      { v: 13, en: 'But we will not boast beyond proper limits, but within the boundaries with which God appointed to us, which reach even to you.', pt: 'Nós, porém, não nos gloriaremos além da medida, mas conforme o padrão da medida que Deus nos designou para chegarmos mesmo até vós;' },
      { v: 14, en: 'For we don’t stretch ourselves too much, as though we didn’t reach to you. For we came even as far as to you with the Good News of Christ,', pt: 'porque não nos estendemos além do que convém, como se não chegássemos a vós, pois já chegamos também até vós no evangelho de Cristo,' },
      { v: 15, en: 'not boasting beyond proper limits in other men’s labors, but having hope that as your faith grows, we will be abundantly enlarged by you in our sphere of influence,', pt: 'não nos gloriando além da medida em trabalhos alheios; antes tendo esperança de que, à proporção que cresce a vossa fé, seremos nós cada vez mais engrandecidos entre vós, conforme a nossa medida,' },
      { v: 16, en: 'so as to preach the Good News even to the parts beyond you, not to boast in what someone else has already done.', pt: 'para anunciar o evangelho nos lugares que estão além de vós, e não em campo de outrem, para não nos gloriarmos no que estava já preparado.' },
      { v: 17, en: 'But “he who boasts, let him boast in the Lord.”', pt: 'Aquele, porém, que se gloria, glorie-se no Senhor.' },
      { v: 18, en: 'For it isn’t he who commends himself who is approved, but whom the Lord commends.', pt: 'Porque não é aprovado aquele que se recomenda a si mesmo, mas sim aquele a quem o Senhor recomenda.' },
    ],
    11: [
      { v: 1, en: 'I wish that you would bear with me in a little foolishness, but indeed you do bear with me.', pt: 'Oxalá me suportásseis um pouco na minha insensatez! Sim, suportai-me ainda.' },
      { v: 2, en: 'For I am jealous over you with a godly jealousy. For I married you to one husband, that I might present you as a pure virgin to Christ.', pt: 'Porque estou zeloso de vós com zelo de Deus; pois vos desposei com um só Esposo, Cristo, para vos apresentar a ele como virgem pura.' },
      { v: 3, en: 'But I am afraid that somehow, as the serpent deceived Eve in his craftiness, so your minds might be corrupted from the simplicity that is in Christ.', pt: 'Mas temo que, assim como a serpente enganou a Eva com a sua astúcia, assim também sejam de alguma sorte corrompidos os vossos entendimentos e se apartem da simplicidade e da pureza que há em Cristo.' },
      { v: 4, en: 'For if he who comes preaches another Jesus, whom we did not preach, or if you receive a different spirit, which you did not receive, or a different “good news”, which you did not accept, you put up with that well enough.', pt: 'Porque, se alguém vem e vos prega outro Jesus que nós não temos pregado, ou se recebeis outro espírito que não recebestes, ou outro evangelho que não abraçastes, de boa mente o suportais!' },
      { v: 5, en: 'For I reckon that I am not at all behind the very best apostles.', pt: 'Ora, julgo que em nada tenho sido inferior aos mais excelentes apóstolos.' },
      { v: 6, en: 'But though I am unskilled in speech, yet I am not unskilled in knowledge. No, in every way we have been revealed to you in all things.', pt: 'Pois ainda que seja rude na palavra, não o sou contudo na ciência; antes, por todos os modos, isto vos temos demonstrado em tudo.' },
      { v: 7, en: 'Or did I commit a sin in humbling myself that you might be exalted, because I preached to you God’s Good News free of charge?', pt: 'Pequei porventura, humilhando-me a mim mesmo, para que vós fôsseis exaltados, porque de graça vos anunciei o evangelho de Deus?' },
      { v: 8, en: 'I robbed other assemblies, taking wages from them that I might serve you.', pt: 'Outras igrejas despojei, recebendo delas salário, para vos servir;' },
      { v: 9, en: 'When I was present with you and was in need, I wasn’t a burden on anyone, for the brothers, when they came from Macedonia, supplied the measure of my need. In everything I kept myself from being burdensome to you, and I will continue to do so.', pt: 'e quando estava presente convosco, e tinha necessidade, a ninguém fui pesado; porque os irmãos, quando vieram da Macedônia, supriram a minha necessidade; e em tudo me guardei, e ainda me guardarei, de vos ser pesado.' },
      { v: 10, en: 'As the truth of Christ is in me, no one will stop me from this boasting in the regions of Achaia.', pt: 'Como a verdade de Cristo está em mim, não me será tirada glória nas regiões da Acaia.' },
      { v: 11, en: 'Why? Because I don’t love you? God knows.', pt: 'Por que? Será porque não vos amo? Deus o sabe.' },
      { v: 12, en: 'But what I do, that I will do, that I may cut off occasion from them that desire an occasion, that in which they boast, they may be found even as we.', pt: 'Ora, o que faço e ainda farei, é para cortar ocasião aos que buscam ocasião; a fim de que, naquilo em que se gloriam, sejam achados assim como nós.' },
      { v: 13, en: 'For such men are false apostles, deceitful workers, masquerading as Christ’s apostles.', pt: 'Pois os tais são falsos apóstolos, obreiros fraudulentos, disfarçando-se em apóstolos de Cristo.' },
      { v: 14, en: 'And no wonder, for even Satan masquerades as an angel of light.', pt: 'E não é de admirar, porquanto o próprio Satanás se disfarça em anjo de luz.' },
      { v: 15, en: 'It is no great thing therefore if his servants also masquerade as servants of righteousness, whose end will be according to their works.', pt: 'Não é muito, pois, que também os seus ministros se disfarcem em ministros da justiça; o fim dos quais será conforme as suas obras.' },
      { v: 16, en: 'I say again, let no one think me foolish. But if so, yet receive me as foolish, that I also may boast a little.', pt: 'Outra vez digo: ninguém me julgue insensato; mas se assim pensais, recebei-me como insensato mesmo, para que eu também me glorie um pouco.' },
      { v: 17, en: 'That which I speak, I don’t speak according to the Lord, but as in foolishness, in this confidence of boasting.', pt: 'O que digo, não o digo segundo o Senhor, mas como por insensatez, nesta confiança de gloriar-me.' },
      { v: 18, en: 'Seeing that many boast after the flesh, I will also boast.', pt: 'Desde que muitos se gloriam segundo a carne, eu também me gloriarei.' },
      { v: 19, en: 'For you bear with the foolish gladly, being wise.', pt: 'Porque, sendo vós sensatos, de boa mente tolerais os insensatos.' },
      { v: 20, en: 'For you bear with a man, if he brings you into bondage, if he devours you, if he takes you captive, if he exalts himself, if he strikes you on the face.', pt: 'Pois se alguém vos escraviza, se alguém vos devora, se alguém vos defrauda, se alguém se ensoberbece, se alguém vos fere no rosto, vós o suportais.' },
      { v: 21, en: 'I speak by way of disparagement, as though we had been weak. Yet in whatever way anyone is bold (I speak in foolishness), I am bold also.', pt: 'Falo com vergonha, como se nós fôssemos fracos; mas naquilo em que alguém se faz ousado, com insensatez falo, também eu sou ousado.' },
      { v: 22, en: 'Are they Hebrews? So am I. Are they Israelites? So am I. Are they the offspring of Abraham? So am I.', pt: 'São hebreus? também eu; são israelitas? também eu; são descendência de Abraão? também eu;' },
      { v: 23, en: 'Are they servants of Christ? (I speak as one beside himself) I am more so; in labors more abundantly, in prisons more abundantly, in stripes above measure, in deaths often.', pt: 'são ministros de Cristo? falo como fora de mim, eu ainda mais; em trabalhos muito mais; em prisões muito mais; em açoites sem medida; em perigo de morte muitas vezes;' },
      { v: 24, en: 'Five times from the Jews I received forty stripes minus one.', pt: 'dos judeus cinco vezes recebi quarenta açoites menos um.' },
      { v: 25, en: 'Three times I was beaten with rods. Once I was stoned. Three times I suffered shipwreck. I have been a night and a day in the deep.', pt: 'Três vezes fui açoitado com varas, uma vez fui apedrejado, três vezes sofri naufrágio, uma noite e um dia passei no abismo;' },
      { v: 26, en: 'I have been in travels often, perils of rivers, perils of robbers, perils from my countrymen, perils from the Gentiles, perils in the city, perils in the wilderness, perils in the sea, perils among false brothers;', pt: 'em viagens muitas vezes, em perigos de rios, em perigos de salteadores, em perigos dos da minha raça, em perigos dos gentios, em perigos na cidade, em perigos no deserto, em perigos no mar, em perigos entre falsos irmãos;' },
      { v: 27, en: 'in labor and travail, in watchings often, in hunger and thirst, in fastings often, and in cold and nakedness.', pt: 'em trabalhos e fadiga, em vigílias muitas vezes, em fome e sede, em jejuns muitas vezes, em frio e nudez.' },
      { v: 28, en: 'Besides those things that are outside, there is that which presses on me daily: anxiety for all the assemblies.', pt: 'Além dessas coisas exteriores, há o que diariamente pesa sobre mim, o cuidado de todas as igrejas.' },
      { v: 29, en: 'Who is weak, and I am not weak? Who is caused to stumble, and I don’t burn with indignation?', pt: 'Quem enfraquece, que eu também não enfraqueça? Quem se escandaliza, que eu me não abrase?' },
      { v: 30, en: 'If I must boast, I will boast of the things that concern my weakness.', pt: 'Se é preciso gloriar-me, gloriar-me-ei no que diz respeito à minha fraqueza.' },
      { v: 31, en: 'The God and Father of the Lord Jesus Christ, he who is blessed forever more, knows that I don’t lie.', pt: 'O Deus e Pai do Senhor Jesus, que é eternamente bendito, sabe que não minto.' },
      { v: 32, en: 'In Damascus the governor under King Aretas guarded the Damascenes’ city, desiring to arrest me.', pt: 'Em Damasco, o que governava sob o rei Aretas guardava a cidade dos damascenos, para me prender;' },
      { v: 33, en: 'Through a window I was let down in a basket by the wall, and escaped his hands.', pt: 'mas por uma janela desceram-me num cesto, muralha abaixo; e assim escapei das suas mãos.' },
    ],
    12: [
      { v: 1, en: 'It is doubtless not profitable for me to boast. For I will come to visions and revelations of the Lord.', pt: 'É necessário gloriar-me, embora não convenha; mas passarei a visões e revelações do Senhor.' },
      { v: 2, en: 'I know a man in Christ, fourteen years ago (whether in the body, I don’t know, or whether out of the body, I don’t know; God knows), such a one caught up into the third heaven.', pt: 'Conheço um homem em Cristo que há catorze anos (se no corpo não sei, se fora do corpo não sei; Deus o sabe) foi arrebatado até o terceiro céu.' },
      { v: 3, en: 'I know such a man (whether in the body, or outside of the body, I don’t know; God knows),', pt: 'Sim, conheço o tal homem (se no corpo, se fora do corpo, não sei: Deus o sabe),' },
      { v: 4, en: 'how he was caught up into Paradise, and heard unspeakable words, which it is not lawful for a man to utter.', pt: 'que foi arrebatado ao paraíso, e ouviu palavras inefáveis, as quais não é lícito ao homem referir.' },
      { v: 5, en: 'On behalf of such a one I will boast, but on my own behalf I will not boast, except in my weaknesses.', pt: 'Desse tal me gloriarei, mas de mim mesmo não me gloriarei, senão nas minhas fraquezas.' },
      { v: 6, en: 'For if I would desire to boast, I will not be foolish; for I will speak the truth. But I refrain, so that no man may think more of me than that which he sees in me, or hears from me.', pt: 'Pois, se quiser gloriar-me, não serei insensato, porque direi a verdade;' },
      { v: 7, en: 'By reason of the exceeding greatness of the revelations, that I should not be exalted excessively, there was given to me a thorn in the flesh, a messenger of Satan to torment me, that I should not be exalted excessively.', pt: 'E, para que me não exaltasse demais pela excelência das revelações, foi-me dado um espinho na carne, a saber, um mensageiro de Satanás para me esbofetear, a fim de que eu não me exalte demais;' },
      { v: 8, en: 'Concerning this thing, I begged the Lord three times that it might depart from me.', pt: 'acerca do qual três vezes roguei ao Senhor que o afastasse de mim;' },
      { v: 9, en: 'He has said to me, “My grace is sufficient for you, for my power is made perfect in weakness.” Most gladly therefore I will rather glory in my weaknesses, that the power of Christ may rest on me.', pt: 'e ele me disse: A minha graça te basta, porque o meu poder se aperfeiçoa na fraqueza. Por isso, de boa vontade antes me gloriarei nas minhas fraquezas, a fim de que repouse sobre mim o poder de Cristo.' },
      { v: 10, en: 'Therefore I take pleasure in weaknesses, in injuries, in necessities, in persecutions, in distresses, for Christ’s sake. For when I am weak, then am I strong.', pt: 'Pelo que sinto prazer nas fraquezas, nas injúrias, nas necessidades, nas perseguições, nas angústias por amor de Cristo. Porque quando estou fraco, então é que sou forte.' },
      { v: 11, en: 'I have become foolish in boasting. You compelled me, for I ought to have been commended by you, for in nothing was I inferior to the very best apostles, though I am nothing.', pt: 'Tornei-me insensato; vós a isso me obrigastes; porque eu devia ser louvado por vós, visto que em nada fui inferior aos demais excelentes apóstolos, ainda que nada sou.' },
      { v: 12, en: 'Truly the signs of an apostle were worked among you in all perseverance, in signs and wonders and mighty works.', pt: 'Os sinais do meu apostolado foram, de fato, operados entre vós com toda a paciência, por sinais, prodígios e milagres.' },
      { v: 13, en: 'For what is there in which you were made inferior to the rest of the assemblies, unless it is that I myself was not a burden to you? Forgive me this wrong.', pt: 'Pois, em que fostes feitos inferiores às outras igrejas, a não ser nisto, que eu mesmo vos não fui pesado? Perdoai-me esta injustiça.' },
      { v: 14, en: 'Behold, this is the third time I am ready to come to you, and I will not be a burden to you; for I seek not your possessions, but you. For the children ought not to save up for the parents, but the parents for the children.', pt: 'Eis que pela terceira vez estou pronto a ir ter convosco, e não vos serei pesado, porque não busco o que é vosso, mas sim a vós; pois não são os filhos que devem entesourar para os pais, mas os pais para os filhos.' },
      { v: 15, en: 'I will most gladly spend and be spent for your souls. If I love you more abundantly, am I loved the less?', pt: 'Eu de muito boa vontade gastarei, e me deixarei gastar pelas vossas almas. Se mais abundantemente vos amo, serei menos amado?' },
      { v: 16, en: 'But be it so, I did not myself burden you. But, being crafty, I caught you with deception.', pt: 'Mas seja assim; eu não vos fui pesado; mas, sendo astuto, vos tomei com dolo.' },
      { v: 17, en: 'Did I take advantage of you by anyone of them whom I have sent to you?', pt: 'Porventura vos explorei por algum daqueles que vos enviei?' },
      { v: 18, en: 'I exhorted Titus, and I sent the brother with him. Did Titus take any advantage of you? Didn’t we walk in the same spirit? Didn’t we walk in the same steps?', pt: 'Exortei a Tito, e enviei com ele o irmão. Porventura Tito vos explorou? Não andamos porventura no mesmo espírito? Não seguimos as mesmas pegadas?' },
      { v: 19, en: 'Again, do you think that we are excusing ourselves to you? In the sight of God we speak in Christ. But all things, beloved, are for your edifying.', pt: 'Há muito, de certo, pensais que nos estamos desculpando convosco. Perante Deus, falamos em Cristo, e tudo isto, amados, é para vossa edificação.' },
      { v: 20, en: 'For I am afraid that by any means, when I come, I might find you not the way I want to, and that I might be found by you as you don’t desire; that by any means there would be strife, jealousy, outbursts of anger, factions, slander, whisperings, proud thoughts, riots;', pt: 'Porque temo que, quando chegar, não vos ache quais eu vos quero, e que eu seja achado por vós qual não me quereis; que de algum modo haja contendas, invejas, iras, porfias, detrações, mexericos, orgulhos, tumultos;' },
      { v: 21, en: 'that again when I come my God would humble me before you, and I would mourn for many of those who have sinned before now, and not repented of the uncleanness and sexual immorality and lustfulness which they committed.', pt: 'e que, quando for outra vez, o meu Deus me humilhe perante vós, e chore eu sobre muitos daqueles que dantes pecaram, e ainda não se arrependeram da impureza, prostituição e lascívia que cometeram.' },
    ],
    13: [
      { v: 1, en: 'This is the third time I am coming to you. “At the mouth of two or three witnesses shall every word be established.”', pt: 'É esta a terceira vez que vou ter convosco. Por boca de duas ou três testemunhas será confirmada toda palavra.' },
      { v: 2, en: 'I have said beforehand, and I do say beforehand, as when I was present the second time, so now, being absent, I write to those who have sinned before now, and to all the rest, that, if I come again, I will not spare;', pt: 'Já o disse quando estava presente a segunda vez, e estando agora ausente torno a dizer aos que antes pecaram e a todos os mais que, se outra vez for, não os pouparei.' },
      { v: 3, en: 'seeing that you seek a proof of Christ who speaks in me; who toward you is not weak, but is powerful in you.', pt: 'visto que buscais uma prova de que Cristo fala em mim; o qual não é fraco para convosco, antes é poderoso entre vós.' },
      { v: 4, en: 'For he was crucified through weakness, yet he lives through the power of God. For we also are weak in him, but we will live with him through the power of God toward you.', pt: 'Porque, ainda que foi crucificado por fraqueza, vive contudo pelo poder de Deus. Pois nós também somos fracos nele, mas viveremos com ele pelo poder de Deus para convosco.' },
      { v: 5, en: 'Examine your own selves, whether you are in the faith. Test your own selves. Or don’t you know as to your own selves, that Jesus Christ is in you?—unless indeed you are disqualified.', pt: 'Examinai-vos a vós mesmos se permaneceis na fé; provai-vos a vós mesmos. Ou não sabeis quanto a vós mesmos, que Jesus Cristo está em vós? Se não é que já estais reprovados.' },
      { v: 6, en: 'But I hope that you will know that we aren’t disqualified.', pt: 'Mas espero que entendereis que nós não somos reprovados.' },
      { v: 7, en: 'Now I pray to God that you do no evil; not that we may appear approved, but that you may do that which is honorable, though we are as reprobate.', pt: 'Ora, rogamos a Deus que não façais mal algum, não para que nós pareçamos aprovados, mas que vós façais o bem, embora nós sejamos como reprovados.' },
      { v: 8, en: 'For we can do nothing against the truth, but for the truth.', pt: 'Porque nada podemos contra a verdade, porém, a favor da verdade.' },
      { v: 9, en: 'For we rejoice when we are weak and you are strong. And this we also pray for, even your perfecting.', pt: 'Pois nos regozijamos quando nós estamos fracos e vós sois fortes; e isto é o que rogamos, a saber, o vosso aperfeiçoamento.' },
      { v: 10, en: 'For this cause I write these things while absent, that I may not deal sharply when present, according to the authority which the Lord gave me for building up, and not for tearing down.', pt: 'Portanto, escrevo estas coisas estando ausente, para que, quando estiver presente, não use de rigor, segundo a autoridade que o Senhor me deu para edificação, e não para destruição.' },
      { v: 11, en: 'Finally, brothers, rejoice. Be perfected, be comforted, be of the same mind, live in peace, and the God of love and peace will be with you.', pt: 'Quanto ao mais, irmãos, regozijai-vos, sede perfeitos, sede consolados, sede de um mesmo parecer, vivei em paz; e o Deus de amor e de paz será convosco.' },
      { v: 12, en: 'Greet one another with a holy kiss.', pt: 'Saudai-vos uns aos outros com ósculo santo. Todos os santos vos saúdam.' },
      { v: 13, en: 'All the saints greet you.', pt: 'A graça do Senhor Jesus Cristo, e o amor de Deus, e a comunhão do Espírito Santo sejam com todos vós.' },
      { v: 14, en: 'The grace of the Lord Jesus Christ, God’s love, and the fellowship of the Holy Spirit, be with you all. Amen.', pt: 'The grace of the Lord Jesus Christ, God’s love, and the fellowship of the Holy Spirit, be with you all. Amen.' },
    ],
  },
};

export default book;
